1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	type Item = { type: string };
13	type Step = { op: string; items: Item[] };
14	type Input = { steps: Step[] };
15	
16	const itemPremium = (item: Item): number => {
17	  const base = BASE_PREMIUMS[item.type] ?? 0;
18	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
19	  return base + firstInsuranceSurcharge;
20	};
21	
22	const quotePremium = (step: Step): number => {
23	  const itemsTotal = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
24	  return Math.ceil(itemsTotal) + PROCESSING_FEE;
25	};
26	
27	export const runScenario = (input: unknown): unknown => {
28	  const { steps } = input as Input;
29	  const results = steps.map((step) => ({ premium: quotePremium(step) }));
30	  return { results };
31	};
