const COMPONENT_TYPES = new Set(["rune"]);
const BLOCK_BASE_PREMIUM = 60;
const BLOCK_SIZE = 3;

const withFirstInsurance = (base: number): number =>
  base + base * FIRST_INSURANCE_SURCHARGE_RATE;

const itemsSubtotal = (items: Item[]): number => {
  const componentsByType = new Map<string, Item[]>();
  let total = 0;
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      const group = componentsByType.get(item.type) ?? [];
      group.push(item);
      componentsByType.set(item.type, group);
    } else {
      total += withFirstInsurance(BASE_PREMIUMS[item.type] ?? 0);
    }
  }
  for (const group of componentsByType.values()) {
    if (group.length === BLOCK_SIZE) {
      total += withFirstInsurance(BLOCK_BASE_PREMIUM);
    } else {
      total += group.reduce(
        (sum, item) => sum + withFirstInsurance(BASE_PREMIUMS[item.type] ?? 0),
        0,
      );
    }
  }
  return total;
};

const quotePremium = (step: Step): number => {
  return Math.ceil(itemsSubtotal(step.items)) + PROCESSING_FEE;
};
